proof_block:
// Pin the abstractified args and the `parse_args` call to stable names so
// both ensures pivot on the same SMT term — without this, each occurrence
// of `parse_args(abstractify_args(args))` reads as a fresh expression and
// the two ensures end up with disjoint quantifier triggers.
let aargs = abstractify_args(args);
let parsed = parse_args(aargs);

// Pre-unfold `abstractify_end_points` on r1's `Some` payload to its
// `Seq::map` definition. This forces z3 to instantiate the inner
// `forall|i|` of `Seq::map` for r1's witness Vec, so its trigger is shared
// with r2's matching unfolding below (rather than living on a r1-only
// trigger that z3 never lines up with r2's side).
match r1 {
    Some(v1) => {
        assert(abstractify_end_points(v1) =~= v1@.map(|i: int, ep: EndPoint| ep@));
    },
    None => {},
}

// Same pre-unfolding for r2 — both unfolded forms now share the same
// `Seq::map` shape, allowing z3 to chain the two ensures'
// `abstractify_end_points(v_k) == parsed.unwrap()` into a pointwise
// equality on the candidate Vecs' views.
match r2 {
    Some(v2) => {
        assert(abstractify_end_points(v2) =~= v2@.map(|i: int, ep: EndPoint| ep@));
    },
    None => {},
}

// When `parse_args(aargs)` is `Some`, its `unwrap()` is literally
// `unchecked_parse_args(aargs)` by the body of `parse_args` (open spec).
// Pin that fact so both ensures' RHS reduce to one shared Seq witness
// instead of two opaque `.unwrap()` calls that z3 treats as black boxes.
assert(parsed is Some ==> parsed.unwrap() == unchecked_parse_args(aargs));
